// frontend/src/components/WeatherOverlay.jsx
import React, { useEffect, useState, useMemo } from "react";

/**
 * Desktop breakpoint hook (≥ 1024px).
 * Returns true on desktop, false on tablets/phones.
 */
function useIsDesktop() {
  const getMatch = () =>
    typeof window !== "undefined" &&
    window.matchMedia("(min-width: 1024px)").matches;

  const [isDesktop, setIsDesktop] = useState(getMatch);

  useEffect(() => {
    const mq = window.matchMedia("(min-width: 1024px)");
    const onChange = (e) => setIsDesktop(e.matches);

    // New + legacy listeners for safety
    mq.addEventListener?.("change", onChange);
    mq.addListener?.(onChange);
    return () => {
      mq.removeEventListener?.("change", onChange);
      mq.removeListener?.(onChange);
    };
  }, []);

  return isDesktop;
}

// --- Import your desktop MP4 overlays ---
import fogday from "./overlays/desktop/fogday.mp4";
import fognight from "./overlays/desktop/fognight.mp4";
import pcday from "./overlays/desktop/pcday.mp4";
import pcnight from "./overlays/desktop/pcnight.mp4";
import clearday from "./overlays/desktop/clearday.mp4";
import clearnight from "./overlays/desktop/clearnight.mp4";
import cloudyday from "./overlays/desktop/cloudyday.mp4";
import cloudynight from "./overlays/desktop/cloudynight.mp4";
import rainday from "./overlays/desktop/rainday.mp4";
import rainnight from "./overlays/desktop/rainnight.mp4";
import thunderstormday from "./overlays/desktop/thunderstormday.mp4";
import thunderstormnight from "./overlays/desktop/thunderstormnight.mp4";
import snowday from "./overlays/desktop/snowday.mp4";
import snownight from "./overlays/desktop/snownight.mp4";

// Keyed map: `${condition}${timeOfDay}` -> file
const OVERLAY_MAP = {
  fogday,
  fognight,
  pcday,
  pcnight,
  clearday,
  clearnight,
  cloudyday,
  cloudynight,
  rainday,
  rainnight,
  thunderstormday,
  thunderstormnight,
  snowday,
  snownight,
};

/**
 * WeatherOverlay
 *
 * Props:
 * - condition: "fog" | "pc" | "clear" | "cloudy" | "rain" | "thunderstorm" | "snow"
 * - timeOfDay: "day" | "night"
 * - opacity: number (0 -> 1), default 1
 *
 * Notes:
 * - Renders nothing on mobile/tablet (< 1024px).
 * - Videos are muted/inline so they autoplay on mobile too, but we’re explicitly desktop-only here.
 * - `pointer-events-none` so the overlay never blocks UI interactions.
 */
export default function WeatherOverlay({
  condition = "clear",
  timeOfDay = "day",
  opacity = 1,
  className = "",
}) {
  const isDesktop = useIsDesktop();

  // Build the key safely and memoize the selected src
  const videoSrc = useMemo(() => {
    const key =
      String(condition).toLowerCase().trim() +
      String(timeOfDay).toLowerCase().trim();
    return OVERLAY_MAP[key] || clearday;
  }, [condition, timeOfDay]);

  if (!isDesktop) return null;

  return (
    <div
      className={`absolute inset-0 z-0 pointer-events-none ${className}`}
      aria-hidden="true"
    >
      <video
        key={videoSrc}       // force re-init when source changes
        autoPlay
        loop
        muted
        playsInline
        preload="auto"
        className="w-full h-full object-cover"
        style={{ opacity }}
      >
        <source src={videoSrc} type="video/mp4" />
      </video>
    </div>
  );
}
